args.query:
SELECT "Patient_description" AS participant_barcode, "gender", "histological_type", "cancer_type_acronym" 
FROM clinical_info 
WHERE "cancer_type_acronym" = 'BRCA' AND "gender" = 'female' AND "histological_type" IS NOT NULL;

